  (function() {
    // 1. Kiểm tra xem query đã có dữ liệu chưa
    const data = get_TraCuu_PhieuXuat.data || [];

    // Nếu chưa chọn phiếu hoặc không có dữ liệu thì hiện thông báo
    if (data.length === 0) {
      return `<div style="font-family: sans-serif; text-align: center; margin-top: 50px; color: gray;">
                <h3>Vui lòng chọn điều kiện và bấm Tra cứu...</h3>
              </div>`;
    }

    // 2. Lấy thông tin chung của Phiếu (Lấy từ dòng đầu tiên)
    const phieu = data[0];

    // 3. Tạo các dòng chi tiết vật tư
    const tableRows = data.map((row, index) => {
      return `
        <tr>
          <td style="text-align: center;">${index + 1}</td>
          <td>${row['Mã BTP'] || ''}</td>
          <td>${row['Mã Vật Tư'] || ''}</td>
          <td>${row['Tên Vật Tư'] || ''}</td>
          <td>${row['Đơn Vị Nhận'] || ''}</td>
          <td>${row['Mã Đơn Hàng'] || ''}</td>
          <td style="text-align: right;"><b>${row['Số Lượng'] || 0}</b></td>
          <td style="text-align: center;">${row['ĐVT'] || ''}</td>
          <td>${row['Ghi Chú'] || ''}</td>
        </tr>
      `;
    }).join('');

    // 4. Lắp ráp thành một trang HTML hoàn chỉnh (Có sẵn CSS)
    return `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="utf-8">
        <style>
          body { font-family: 'Arial', sans-serif; padding: 20px; color: #333; }
          h2 { text-align: center; margin-bottom: 5px; }
          .header-info { display: flex; justify-content: space-between; margin-bottom: 20px; font-size: 14px; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 13px; }
          th, td { border: 1px solid #000; padding: 8px; text-align: left; }
          th { background-color: #f2f2f2; text-align: center; }
          .footer { display: flex; justify-content: space-between; text-align: center; margin-top: 50px; }
        </style>
      </head>
      <body>
        <h2>PHIẾU XUẤT KHO NGUYÊN LIỆU</h2>
        <div style="text-align: center; margin-bottom: 20px;">
          <i>Ngày xuất: ${phieu['Ngày Xuất'] || ''}</i>
        </div>

        <div class="header-info">
          <div>
            <p><b>Mã phiếu xuất:</b> ${phieu['Mã Phiếu Xuất'] || ''}</p>
            <p><b>Xuất cho bộ phận:</b> ${phieu['Đơn Vị Nhận'] || ''}</p>
          </div>
          <div>
            <p><b>Người nhận hàng:</b> ${phieu['Người Nhận'] || ''}</p>
          </div>
        </div>

        <table>
          <thead>
            <tr>
              <th width="5%">STT</th>
              <th width="10%">Mã BTP</th>
              <th width="10%">Mã VT</th>
              <th width="20%">Tên Vật Tư</th>
              <th width="15%">Đơn Vị Nhận</th>
              <th width="10%">Mã Đơn Hàng</th>
              <th width="10%">Số Lượng</th>
              <th width="5%">ĐVT</th>
              <th width="15%">Ghi Chú</th>
            </tr>
          </thead>
          <tbody>
            ${tableRows}
          </tbody>
        </table>

        <div class="footer">
          <div>
            <b>Người lập phiếu</b><br><br><br><span>(Ký, ghi rõ họ tên)</span>
          </div>
          <div>
            <b>Người nhận hàng</b><br><br><br><span>(Ký, ghi rõ họ tên)</span>
          </div>
          <div>
            <b>Thủ kho</b><br><br><br><span>(Ký, ghi rõ họ tên)</span>
          </div>
        </div>
      </body>
      </html>
    `;
  })()
}}
